// ============================================================
// Build 3D Object Job List
// ============================================================
// Reads each card JSON from the deck and builds a job list
// for 3D object generation. Skips cards that already have
// GLB files if SkipExisting is true.
// ============================================================

const fs = require('fs');
const path = require('path');

const params = $('Set Global Parameters').first().json;
const testCardFilter = (params.TestCardFilter || '').trim();
const orientations = (params.Orientations || 'upright,reversed,between').split(',').map(s => s.trim());
const skipExisting = params.SkipExisting !== 'false';

const raw = $input.first().json;
const deck = raw.data !== undefined ? raw.data : raw;

const deckDir = ((deck.Assets && deck.Assets.Directory)
  ? deck.Assets.Directory
  : 'D:/data/cards/Standard').replace(/\//g, path.sep);

const cardRefs = deck.Cards;
if (!cardRefs || cardRefs.length === 0) {
  throw new Error('[Build 3D Job List] No Cards found in Deck.json.');
}

const filteredCards = testCardFilter
  ? cardRefs.filter(c => c.Card === testCardFilter)
  : cardRefs;

if (filteredCards.length === 0) {
  throw new Error('[Build 3D Job List] No cards matched filter: ' + JSON.stringify(testCardFilter));
}

const jobs = [];

for (const cardRef of filteredCards) {
  const cardName = cardRef.Card;
  const cardSlug = cardName.replace(/[()]/g, '').replace(/\s+/g, '_');
  const cardFilePath = path.join(deckDir, cardRef.File.replace(/\//g, path.sep));

  let cardRaw;
  try {
    cardRaw = JSON.parse(fs.readFileSync(cardFilePath, 'utf8').replace(/^\uFEFF/, ''));
  } catch(e) {
    console.warn('[Build 3D Job List] Cannot read card: ' + cardName + ': ' + e.message);
    continue;
  }

  const card = cardRaw['data.Cards'] || cardRaw;
  const cardDir = (card.Directory || path.join(deckDir, 'Cards')).replace(/\//g, path.sep);
  const records = card.records || [];

  for (const orientation of orientations) {
    const record = records.find(r => r.Orientation === orientation);
    if (!record) continue;

    const glbFilename = 'MODEL_' + cardSlug + '_' + orientation + '.glb';
    const glbPath = path.join(cardDir, glbFilename);

    // Skip if GLB already exists
    if (skipExisting && fs.existsSync(glbPath)) {
      console.warn('[Build 3D Job List] GLB exists, skipping: ' + cardName + ' ' + orientation);
      continue;
    }

    // Build the positive prompt from the card description
    const description = record.Description || cardName + ' tarot card character';
    const positivePrompt = 'Front-facing portrait of ' + description
      + ', centered, full body, simple flat gray background, studio lighting, '
      + 'symmetrical pose, high detail, 3D reference sheet style, single character';
    const negativePrompt = 'blurry, low quality, multiple characters, complex background, '
      + 'text, watermark, side view, back view, cropped, out of frame';

    jobs.push({
      CardName: cardName,
      CardSlug: cardSlug,
      Orientation: orientation,
      CardDir: cardDir,
      CardFilePath: cardFilePath,
      PositivePrompt: positivePrompt,
      NegativePrompt: negativePrompt,
      RefFilename: '3DREF_' + cardSlug + '_' + orientation + '.png',
      GLBFilename: glbFilename,
      OBJFilename: 'MODEL_' + cardSlug + '_' + orientation + '.obj'
    });
  }
}

if (jobs.length === 0) {
  throw new Error(
    '[Build 3D Job List] No jobs created. '
    + 'All cards may already have GLB files, or TestCardFilter matched nothing. '
    + 'Set SkipExisting=false to regenerate.'
  );
}

console.warn('[Build 3D Job List] Created ' + jobs.length + ' jobs.');
return jobs.map(j => ({ json: j }));

// ============================================================
// Generate All 3D Models
// ============================================================
// For each job, submits a chained ComfyUI workflow that:
//   Stage 1: Generates a 3D-optimized character image (HiDream I1)
//   Stage 2: Removes the background (BiRefNetRMBG)
//   Stage 3: Generates a 3D mesh (TripoSR)
// Then polls for completion and records the output.
// ============================================================

const http = require('http');
const fs = require('fs');
const path = require('path');

// --- HTTP helpers (require('http'), NOT axios) ---
const httpRequest = (method, urlStr, body) => new Promise((resolve, reject) => {
  const m = urlStr.match(/^(https?):(\/\/)([^:/]+)(?::(\d+))?(\/[^?]*)?(\?.*)?$/);
  if (!m) return reject(new Error('Bad URL: ' + urlStr));
  const hostname = m[3];
  const port = m[4] ? parseInt(m[4]) : 80;
  const reqPath = (m[5] || '/') + (m[6] || '');
  const options = { hostname, port, path: reqPath, method, headers: {} };
  if (body) {
    options.headers['Content-Type'] = 'application/json';
    options.headers['Content-Length'] = Buffer.byteLength(body);
  }
  const req = http.request(options, (res) => {
    let data = '';
    res.on('data', (chunk) => { data += chunk; });
    res.on('end', () => {
      try { resolve(JSON.parse(data)); } catch(e) { resolve(data); }
    });
  });
  req.on('error', reject);
  if (body) req.write(body);
  req.end();
});
const httpPost = (url, bodyObj) => httpRequest('POST', url, JSON.stringify(bodyObj));
const httpGet  = (url)          => httpRequest('GET',  url, null);

const sleep = ms => new Promise(r => setTimeout(r, ms));

const params = $('Set Global Parameters').first().json;
const comfyAPI = (params.ComfyUIAPI || 'http://127.0.0.1:8188').replace(/\/$/, '');
const tripoResolution = parseInt(params.TripoSRResolution || '512');

const allJobs = $input.all().map(item => item.json);
const results = [];

for (let idx = 0; idx < allJobs.length; idx++) {
  const job = allJobs[idx];
  console.warn('[3D Gen] (' + (idx+1) + '/' + allJobs.length + ') ' + job.CardName + ' ' + job.Orientation);

  // Unique seed per job for variety
  const seed = Math.floor(Math.random() * 999999999999);

  // Build the ComfyUI API prompt - 3-stage chained workflow
  // Stage 1: Image generation (HiDream I1)
  // Stage 2: Background removal (BiRefNetRMBG)
  // Stage 3: TripoSR mesh generation
  const comfyPrompt = {
    // --- Stage 1: Image Generation ---
    "1": {
      "inputs": {
        "unet_name": "hidream_i1_full_fp8.safetensors",
        "weight_dtype": "default"
      },
      "class_type": "UNETLoader",
      "_meta": { "title": "Load HiDream I1" }
    },
    "2": {
      "inputs": {
        "clip_name1": "clip_l_hidream.safetensors",
        "clip_name2": "clip_g_hidream.safetensors",
        "clip_name3": "t5xxl_fp8_e4m3fn_scaled.safetensors",
        "clip_name4": "llama_3.1_8b_instruct_fp8_scaled.safetensors"
      },
      "class_type": "QuadrupleCLIPLoader",
      "_meta": { "title": "Load CLIP Encoders" }
    },
    "3": {
      "inputs": {
        "text": job.PositivePrompt,
        "clip": ["2", 0]
      },
      "class_type": "CLIPTextEncode",
      "_meta": { "title": "Positive Prompt" }
    },
    "4": {
      "inputs": {
        "text": job.NegativePrompt,
        "clip": ["2", 0]
      },
      "class_type": "CLIPTextEncode",
      "_meta": { "title": "Negative Prompt" }
    },
    "5": {
      "inputs": {
        "shift": 3.0,
        "model": ["1", 0]
      },
      "class_type": "ModelSamplingSD3",
      "_meta": { "title": "ModelSamplingSD3" }
    },
    "6": {
      "inputs": {
        "width": 1024,
        "height": 1024,
        "batch_size": 1
      },
      "class_type": "EmptySD3LatentImage",
      "_meta": { "title": "Empty Latent" }
    },
    "7": {
      "inputs": {
        "seed": seed,
        "steps": 30,
        "cfg": 7,
        "sampler_name": "euler",
        "scheduler": "normal",
        "denoise": 1,
        "model": ["5", 0],
        "positive": ["3", 0],
        "negative": ["4", 0],
        "latent_image": ["6", 0]
      },
      "class_type": "KSampler",
      "_meta": { "title": "KSampler" }
    },
    "8": {
      "inputs": {
        "vae_name": "ae.safetensors"
      },
      "class_type": "VAELoader",
      "_meta": { "title": "Load VAE" }
    },
    "9": {
      "inputs": {
        "samples": ["7", 0],
        "vae": ["8", 0]
      },
      "class_type": "VAEDecode",
      "_meta": { "title": "VAE Decode" }
    },
    // Save the 3D reference image
    "10": {
      "inputs": {
        "filename_prefix": "3DREF_" + job.CardSlug + "_" + job.Orientation,
        "images": ["9", 0]
      },
      "class_type": "SaveImage",
      "_meta": { "title": "Save 3D Ref Image" }
    },
    // --- Stage 2: Background Removal ---
    "11": {
      "inputs": {
        "image": ["9", 0],
        "model": "BiRefNet-general"
      },
      "class_type": "BiRefNetRMBG",
      "_meta": { "title": "Remove Background" }
    },
    // --- Stage 3: TripoSR 3D Generation ---
    "12": {
      "inputs": {
        "chunk_size": 8192
      },
      "class_type": "LoadTripoSRModel",
      "_meta": { "title": "Load TripoSR Model" }
    },
    "13": {
      "inputs": {
        "model": ["12", 0],
        "image": ["11", 0],
        "mask": ["11", 1],
        "resolution": tripoResolution,
        "threshold": 25.0,
        "device": "auto"
      },
      "class_type": "TripoSRSampler",
      "_meta": { "title": "TripoSR Sampler" }
    },
    "14": {
      "inputs": {
        "mesh": ["13", 0],
        "filename_prefix": "MODEL_" + job.CardSlug + "_" + job.Orientation
      },
      "class_type": "SaveTripoSRMesh",
      "_meta": { "title": "Save 3D Mesh (GLB)" }
    }
  };

  // Submit to ComfyUI
  let submitData;
  try {
    submitData = await httpPost(comfyAPI + '/prompt', { prompt: comfyPrompt });
  } catch(e) {
    console.warn('[3D Gen] Submit failed for ' + job.CardName + ': ' + e.message);
    results.push({ ...job, Status: 'failed', Reason: 'Submit error: ' + e.message });
    continue;
  }

  if (submitData.error) {
    console.warn('[3D Gen] ComfyUI error: ' + JSON.stringify(submitData.error));
    results.push({ ...job, Status: 'failed', Reason: 'ComfyUI error: ' + JSON.stringify(submitData.error).substring(0, 500) });
    continue;
  }

  const promptId = submitData.prompt_id;
  if (!promptId) {
    results.push({ ...job, Status: 'failed', Reason: 'No prompt_id returned' });
    continue;
  }

  // Poll for completion (up to 30 min per job)
  let done = false;
  const maxAttempts = 360; // 360 x 5s = 30 min
  for (let attempt = 0; attempt < maxAttempts && !done; attempt++) {
    await sleep(5000);
    try {
      const historyData = await httpGet(comfyAPI + '/history/' + promptId);
      const entry = historyData[promptId];
      if (!entry) continue;

      // Check if the workflow completed (node 14 is the output node)
      if (entry.status && entry.status.completed) {
        // Check for errors
        if (entry.status.status_str === 'error') {
          const nodeErrors = entry.status.messages
            ? entry.status.messages.filter(m => m[0] === 'execution_error').map(m => m[1])
            : [];
          const errMsg = nodeErrors.length > 0
            ? JSON.stringify(nodeErrors[0]).substring(0, 500)
            : 'Unknown ComfyUI execution error';
          results.push({ ...job, Status: 'failed', Reason: errMsg });
          done = true;
          continue;
        }

        // Success
        const outputs = entry.outputs || {};
        const savedImage = outputs['10'];
        const savedMesh = outputs['14'];

        results.push({
          ...job,
          Status: 'generated',
          PromptId: promptId,
          RefImageOutput: savedImage ? JSON.stringify(savedImage).substring(0, 200) : 'unknown',
          MeshOutput: savedMesh ? JSON.stringify(savedMesh).substring(0, 200) : 'unknown'
        });
        done = true;
      }
    } catch(e) {
      // Polling error - continue retrying
      if (attempt % 12 === 0) {
        console.warn('[3D Gen] Poll attempt ' + attempt + ' for ' + job.CardName + ': ' + e.message);
      }
    }
  }

  if (!done) {
    results.push({ ...job, Status: 'timeout', Reason: 'Timed out after 30 min' });
  }
}

if (results.length === 0) {
  throw new Error('[Generate 3D Models] No results produced. Check ComfyUI is running.');
}

return results.map(r => ({ json: r }));

// ============================================================
// Convert GLB to OBJ
// ============================================================
// For each generated GLB file, converts to OBJ format using
// Python trimesh. Also copies GLB files from ComfyUI output
// directory to the card directory.
// ============================================================

const fs = require('fs');
const path = require('path');
const { execFileSync } = require('child_process');

const allItems = $input.all().map(item => item.json);
const results = [];

// ComfyUI saves meshes to its output directory
const comfyOutputDir = 'D:/ComfyUI_windows_portable/ComfyUI/output';

for (const item of allItems) {
  if (item.Status !== 'generated') {
    results.push(item);
    continue;
  }

  const cardDir = item.CardDir;
  const glbFilename = item.GLBFilename;
  const objFilename = item.OBJFilename;
  const glbDestPath = path.join(cardDir, glbFilename);
  const objDestPath = path.join(cardDir, objFilename);

  // Find the GLB file in ComfyUI output
  // SaveTripoSRMesh saves as {filename_prefix}_{5-digit-number}.glb
  const prefix = 'MODEL_' + item.CardSlug + '_' + item.Orientation;
  let glbSourcePath = null;

  try {
    const outputFiles = fs.readdirSync(comfyOutputDir);
    const matches = outputFiles
      .filter(f => f.startsWith(prefix) && f.endsWith('.glb'))
      .sort()
      .reverse(); // Most recent first
    if (matches.length > 0) {
      glbSourcePath = path.join(comfyOutputDir, matches[0]);
    }
  } catch(e) {
    results.push({ ...item, Status: 'failed', Reason: 'Cannot read ComfyUI output dir: ' + e.message });
    continue;
  }

  if (!glbSourcePath || !fs.existsSync(glbSourcePath)) {
    results.push({ ...item, Status: 'failed', Reason: 'GLB not found in ComfyUI output for prefix: ' + prefix });
    continue;
  }

  // Copy GLB to card directory
  try {
    fs.mkdirSync(cardDir, { recursive: true });
    fs.copyFileSync(glbSourcePath, glbDestPath);
  } catch(e) {
    results.push({ ...item, Status: 'failed', Reason: 'Failed to copy GLB: ' + e.message });
    continue;
  }

  // Also copy the 3D reference image from ComfyUI output
  const refPrefix = '3DREF_' + item.CardSlug + '_' + item.Orientation;
  try {
    const outputFiles = fs.readdirSync(comfyOutputDir);
    const refMatches = outputFiles
      .filter(f => f.startsWith(refPrefix) && f.endsWith('.png'))
      .sort()
      .reverse();
    if (refMatches.length > 0) {
      const refSourcePath = path.join(comfyOutputDir, refMatches[0]);
      const refDestPath = path.join(cardDir, item.RefFilename);
      fs.copyFileSync(refSourcePath, refDestPath);
    }
  } catch(e) {
    console.warn('[GLB->OBJ] Could not copy ref image: ' + e.message);
  }

  // Convert GLB to OBJ using Python trimesh via execFileSync
  // execFileSync avoids shell injection by passing args as array
  try {
    const pyCode = 'import trimesh, sys; m = trimesh.load(sys.argv[1]); '
      + 'm = trimesh.util.concatenate(list(m.geometry.values())) if hasattr(m, "geometry") and isinstance(m.geometry, dict) else m; '
      + 'm.export(sys.argv[2])';

    execFileSync('python', [
      '-c', pyCode,
      glbDestPath.replace(/\\/g, '/'),
      objDestPath.replace(/\\/g, '/')
    ], { encoding: 'utf8', timeout: 60000 });

    const glbSize = fs.statSync(glbDestPath).size;
    const objSize = fs.existsSync(objDestPath) ? fs.statSync(objDestPath).size : 0;

    results.push({
      ...item,
      Status: 'completed',
      GLBPath: glbDestPath,
      OBJPath: objDestPath,
      GLBSizeKB: Math.round(glbSize / 1024),
      OBJSizeKB: Math.round(objSize / 1024)
    });
  } catch(e) {
    // GLB was saved but OBJ conversion failed - still partial success
    results.push({
      ...item,
      Status: 'partial',
      GLBPath: glbDestPath,
      Reason: 'GLB saved but OBJ conversion failed: ' + e.message.substring(0, 300)
    });
  }
}

return results.map(r => ({ json: r }));

// ============================================================
// Report Results
// ============================================================

const allItems = $input.all().map(item => item.json);

const completed = allItems.filter(i => i.Status === 'completed');
const partial   = allItems.filter(i => i.Status === 'partial');
const failed    = allItems.filter(i => i.Status === 'failed');
const timeout   = allItems.filter(i => i.Status === 'timeout');

const summary = {
  Total: allItems.length,
  Completed: completed.length,
  Partial: partial.length,
  Failed: failed.length,
  Timeout: timeout.length,
  Details: allItems.map(i => ({
    Card: i.CardName,
    Orientation: i.Orientation,
    Status: i.Status,
    GLBPath: i.GLBPath || '',
    OBJPath: i.OBJPath || '',
    GLBSizeKB: i.GLBSizeKB || 0,
    OBJSizeKB: i.OBJSizeKB || 0,
    Reason: i.Reason || ''
  }))
};

console.warn('=== 3D Object Generation Complete ===');
console.warn('Completed: ' + completed.length + '  Partial: ' + partial.length
  + '  Failed: ' + failed.length + '  Timeout: ' + timeout.length);

if (failed.length > 0) {
  console.warn('Failed cards:');
  for (const f of failed) {
    console.warn('  - ' + f.CardName + ' ' + f.Orientation + ': ' + (f.Reason || 'unknown'));
  }
}

return [{ json: summary }];
